/* ===== Event Cards (Termine) ===== */
.page-content--wide {
  max-width: 860px;
}
.event {
  background: var(--white);
  border: 1px solid var(--gray-100);
  border-radius: var(--radius);
  overflow: hidden;
  margin-bottom: 32px;
  transition: box-shadow .2s;
}
.event:hover {
  box-shadow: 0 4px 20px rgba(15,26,46,.08);
}
.event__image {
  width: 100%;
  overflow: hidden;
}
.event__image img {
  width: 100%;
  height: auto;
  display: block;
}
.event__body {
  padding: 28px 32px 32px;
}
.event__meta {
  display: flex;
  align-items: center;
  gap: 10px;
  margin-bottom: 10px;
}
.event__date {
  font-size: .78rem;
  font-weight: 600;
  color: var(--polizei-mid);
  text-transform: uppercase;
  letter-spacing: .5px;
}
.event__title {
  font-size: 1.25rem;
  font-weight: 800;
  color: var(--gray-900);
  line-height: 1.3;
  margin-bottom: 14px;
}
.event__intro {
  font-size: .92rem;
  color: var(--gray-700);
  line-height: 1.65;
  margin-bottom: 20px;
}
.event__heading {
  font-size: .95rem;
  font-weight: 700;
  color: var(--gray-900);
  margin-bottom: 8px;
  margin-top: 20px;
}
.event__text {
  font-size: .88rem;
  color: var(--gray-700);
  line-height: 1.65;
}
.event__table-wrap {
  overflow-x: auto;
  margin-bottom: 8px;
}
.event__table {
  width: 100%;
  border-collapse: collapse;
  font-size: .85rem;
}
.event__table th {
  text-align: left;
  font-weight: 600;
  color: var(--gray-500);
  font-size: .75rem;
  text-transform: uppercase;
  letter-spacing: .5px;
  padding: 8px 14px;
  border-bottom: 2px solid var(--gray-100);
}
.event__table td {
  padding: 10px 14px;
  color: var(--gray-700);
  border-bottom: 1px solid var(--gray-100);
}
.event__table tr:last-child td {
  border-bottom: none;
}
.event__table td:first-child {
  font-weight: 600;
  color: var(--gray-900);
}
.event__author {
  margin-top: 20px;
  padding-top: 16px;
  border-top: 1px solid var(--gray-100);
  font-size: .82rem;
  font-style: italic;
  color: var(--gray-300);
}

/* ===== Tag: Übung ===== */
.article__tag--uebung {
  background: rgba(34,139,34,.1);
  color: #228b22;
}
.article__tag--veranstaltung {
  background: rgba(0,90,156,.1);
  color: var(--polizei-mid);
}

@media (max-width: 768px) {
  .event__body { padding: 20px; }
  .event__title { font-size: 1.1rem; }
}

