     1→/* Local Fonts — DSGVO-konform, kein Google-Aufruf */
     2→@font-face {
     3→  font-family: 'Inter';
     4→  font-style: normal;
     5→  font-weight: 300 800;
     6→  font-display: swap;
     7→  src: url(/fonts/inter-latin.woff2) format('woff2');
     8→  unicode-range: U+0000-00FF, U+0131, U+0152-0153, U+02BB-02BC, U+02C6, U+02DA, U+02DC, U+0304, U+0308, U+0329, U+2000-206F, U+20AC, U+2122, U+2191, U+2193, U+2212, U+2215, U+FEFF, U+FFFD;
     9→}
    10→@font-face {
    11→  font-family: 'Inter';
    12→  font-style: normal;
    13→  font-weight: 300 800;
    14→  font-display: swap;
    15→  src: url(/fonts/inter-latin-ext.woff2) format('woff2');
    16→  unicode-range: U+0100-02BA, U+02BD-02C5, U+02C7-02CC, U+02CE-02D7, U+02DD-02FF, U+0304, U+0308, U+0329, U+1D00-1DBF, U+1E00-1E9F, U+1EF2-1EFF, U+2020, U+20A0-20AB, U+20AD-20C0, U+2113, U+2C60-2C7F, U+A720-A7FF;
    17→}
    18→@font-face {
    19→  font-family: 'JetBrains Mono';
    20→  font-style: normal;
    21→  font-weight: 400 500;
    22→  font-display: swap;
    23→  src: url(/fonts/jetbrains-mono-latin.woff2) format('woff2');
    24→  unicode-range: U+0000-00FF, U+0131, U+0152-0153, U+02BB-02BC, U+02C6, U+02DA, U+02DC, U+0304, U+0308, U+0329, U+2000-206F, U+20AC, U+2122, U+2191, U+2193, U+2212, U+2215, U+FEFF, U+FFFD;
    25→}
    26→@font-face {
    27→  font-family: 'JetBrains Mono';
    28→  font-style: normal;
    29→  font-weight: 400 500;
    30→  font-display: swap;
    31→  src: url(/fonts/jetbrains-mono-latin-ext.woff2) format('woff2');
    32→  unicode-range: U+0100-02BA, U+02BD-02C5, U+02C7-02CC, U+02CE-02D7, U+02DD-02FF, U+0304, U+0308, U+0329, U+1D00-1DBF, U+1E00-1E9F, U+1EF2-1EFF, U+2020, U+20A0-20AB, U+20AD-20C0, U+2113, U+2C60-2C7F, U+A720-A7FF;
    33→}
    34→
    35→*, *::before, *::after { margin: 0; padding: 0; box-sizing: border-box; }
    36→
    37→:root {
    38→  /* Austrian Police Uniform Blues — derived from Bundespolizei dunkelblau */
    39→  --polizei-dark:    #0F1A2E;
    40→  --polizei-navy:    #1B2A4A;
    41→  --polizei-blue:    #2B4370;
    42→  --polizei-mid:     #3A5A8C;
    43→  --polizei-light:   #4A7AB5;
    44→  --polizei-pale:    #6B9DD6;
    45→
    46→  /* Austrian flag red + BOS-ARSA logo gold */
    47→  --at-red:          #C8102E;
    48→  --bos-gold:        #D4A843;
    49→  --bos-gold-light:  #E0BE6A;
    50→  --bos-gold-dark:   #B8912E;
    51→
    52→  /* Neutrals */
    53→  --white:           #FFFFFF;
    54→  --off-white:       #F4F6F9;
    55→  --gray-100:        #E8ECF1;
    56→  --gray-200:        #D0D7E0;
    57→  --gray-300:        #A8B4C2;
    58→  --gray-500:        #5C6B7F;
    59→  --gray-700:        #374151;
    60→  --gray-900:        #111827;
    61→
    62→  --font-main: 'Inter', -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif;
    63→  --font-mono: 'JetBrains Mono', monospace;
    64→  --container: 1280px;
    65→  --nav-h: 72px;
    66→  --radius: 2px;
    67→}
    68→
    69→html { scroll-behavior: smooth; scroll-padding-top: var(--nav-h); }
    70→
    71→body {
    72→  font-family: var(--font-main);
    73→  color: var(--gray-700);
    74→  background: var(--off-white);
    75→  line-height: 1.65;
    76→  -webkit-font-smoothing: antialiased;
    77→}
    78→
    79→img { max-width: 100%; display: block; }
    80→a { color: var(--polizei-light); text-decoration: none; transition: color .2s; }
    81→a:hover { color: var(--polizei-pale); }
    82→a:focus-visible { outline: 2px solid var(--polizei-light); outline-offset: 2px; }
    83→
    84→.container { max-width: var(--container); margin: 0 auto; padding: 0 24px; }
    85→
    86→/* ===== Scroll Reveal ===== */
    87→.reveal {
    88→  opacity: 0;
    89→  transform: translateY(24px);
    90→  transition: opacity .6s ease, transform .6s ease;
    91→}
    92→.reveal.visible { opacity: 1; transform: none; }
    93→
    94→/* ===== Nav ===== */
    95→.nav {
    96→  position: fixed; top: 0; left: 0; right: 0; z-index: 1000;
    97→  background: var(--polizei-dark);
    98→  height: var(--nav-h);
    99→  transition: box-shadow .3s, background .3s;
   100→  border-bottom: 1px solid rgba(255,255,255,.04);
   101→}
   102→.nav.scrolled { box-shadow: 0 4px 24px rgba(0,0,0,.35); }
   103→.nav__inner { display: flex; align-items: center; justify-content: space-between; height: 100%; }
   104→
   105→.nav__brand {
   106→  display: flex; align-items: center; gap: 12px;
   107→  text-decoration: none; color: var(--white);
   108→}
   109→.nav__brand:hover { color: var(--white); }
   110→.nav__brand-logo {
   111→  height: 44px;
   112→  width: auto;
   113→  border-radius: var(--radius);
   114→}
   115→.nav__brand-text {
   116→  display: flex; flex-direction: column; line-height: 1.15;
   117→}
   118→.nav__brand-name {
   119→  font-weight: 800; font-size: 1.25rem; letter-spacing: .5px;
   120→  color: var(--bos-gold);
   121→}
   122→.nav__brand-sub {
   123→  font-size: .65rem; font-weight: 400; letter-spacing: .3px;
   124→  color: var(--gray-300); white-space: nowrap;
   125→}
   126→
   127→.nav__links { display: flex; align-items: center; gap: 2px; list-style: none; }
   128→.nav__links a {
   129→  display: block; padding: 8px 12px;
   130→  color: var(--gray-300); font-size: .82rem; font-weight: 500;
   131→  letter-spacing: .2px; border-radius: var(--radius);
   132→  transition: color .2s, background .2s; text-decoration: none;
   133→}
   134→.nav__links a:hover { color: var(--white); background: rgba(255,255,255,.06); }
   135→.nav__links a.active { color: var(--bos-gold); }
   136→
   137→.nav__hamburger {
   138→  display: none; flex-direction: column; justify-content: center;
   139→  gap: 5px; width: 40px; height: 40px;
   140→  background: none; border: none; cursor: pointer; padding: 6px;
   141→}
   142→.nav__hamburger span {
   143→  display: block; width: 100%; height: 2px;
   144→  background: var(--gray-300); transition: transform .3s, opacity .3s;
   145→  border-radius: 1px;
   146→}
   147→.nav__hamburger.active span:nth-child(1) { transform: translateY(7px) rotate(45deg); }
   148→.nav__hamburger.active span:nth-child(2) { opacity: 0; }
   149→.nav__hamburger.active span:nth-child(3) { transform: translateY(-7px) rotate(-45deg); }
   150→
   151→/* ===== Buttons ===== */
   152→.btn {
   153→  display: inline-flex; align-items: center; gap: 8px;
   154→  padding: 13px 28px; font-family: var(--font-main);
   155→  font-size: .875rem; font-weight: 600; letter-spacing: .3px;
   156→  border: 2px solid transparent; border-radius: var(--radius);
   157→  cursor: pointer; transition: all .2s; text-decoration: none;
   158→}
   159→.btn:focus-visible { outline: 2px solid var(--polizei-light); outline-offset: 2px; }
   160→
   161→.btn--gold {
   162→  background: var(--bos-gold); color: var(--polizei-dark);
   163→  border-color: var(--bos-gold);
   164→}
   165→.btn--gold:hover {
   166→  background: var(--bos-gold-light); border-color: var(--bos-gold-light);
   167→  color: var(--polizei-dark); transform: translateY(-1px);
   168→  box-shadow: 0 4px 16px rgba(212,168,67,.25);
   169→}
   170→
   171→.btn--outline-white {
   172→  background: transparent; color: var(--white);
   173→  border-color: rgba(255,255,255,.25);
   174→}
   175→.btn--outline-white:hover {
   176→  border-color: var(--white); color: var(--white);
   177→  background: rgba(255,255,255,.05); transform: translateY(-1px);
   178→}
   179→
   180→.btn--polizei {
   181→  background: var(--polizei-mid); color: var(--white);
   182→  border-color: var(--polizei-mid);
   183→}
   184→.btn--polizei:hover {
   185→  background: var(--polizei-light); border-color: var(--polizei-light);
   186→  color: var(--white); transform: translateY(-1px);
   187→  box-shadow: 0 4px 16px rgba(74,122,181,.25);
   188→}
   189→
   190→/* ===== Austrian flag stripe accent ===== */
   191→.at-stripe {
   192→  height: 4px; width: 100%;
   193→  background: linear-gradient(90deg, var(--at-red) 33.33%, var(--white) 33.33%, var(--white) 66.66%, var(--at-red) 66.66%);
   194→}
   195→
   196→/* ===== Sections ===== */
   197→.section { padding: 96px 0; }
   198→.section--alt { background: var(--white); }
   199→.section--dark {
   200→  background: linear-gradient(170deg, var(--polizei-navy) 0%, var(--polizei-dark) 100%);
   201→  color: var(--white);
   202→}
   203→
   204→.section__header { text-align: center; margin-bottom: 56px; }
   205→.section__label {
   206→  display: inline-block;
   207→  font-family: var(--font-mono); font-size: .72rem;
   208→  letter-spacing: 3px; text-transform: uppercase;
   209→  color: var(--bos-gold); margin-bottom: 10px;
   210→}
   211→.section__title {
   212→  font-size: clamp(1.6rem, 3.5vw, 2.2rem);
   213→  font-weight: 800; line-height: 1.2; color: var(--gray-900);
   214→}
   215→.section--dark .section__title { color: var(--white); }
   216→.section__rule {
   217→  width: 48px; height: 3px; background: var(--bos-gold);
   218→  margin: 14px auto 0; border-radius: 1px;
   219→}
   220→.section__intro {
   221→  max-width: 640px; margin: 20px auto 0;
   222→  color: var(--gray-500); font-size: 1rem; line-height: 1.7; text-align: center;
   223→}
   224→.section--dark .section__intro { color: var(--gray-300); }
   225→
   226→/* ===== Footer ===== */
   227→.footer {
   228→  background: var(--polizei-dark); color: var(--gray-300); padding: 56px 0 0;
   229→}
   230→.footer__inner { display: grid; grid-template-columns: 2fr 1fr 1fr; gap: 48px; }
   231→.footer__brand {
   232→  display: flex; align-items: center; gap: 12px; margin-bottom: 18px;
   233→}
   234→.footer__brand-logo { height: 40px; width: auto; border-radius: 2px; }
   235→.footer__brand-name {
   236→  font-weight: 800; font-size: 1.1rem; color: var(--bos-gold); letter-spacing: .5px;
   237→}
   238→.footer__org-name {
   239→  font-size: .84rem; line-height: 1.6;
   240→  color: rgba(168,180,194,.6); margin-bottom: 16px;
   241→}
   242→.footer__details {
   243→  font-size: .82rem; line-height: 1.75; color: rgba(168,180,194,.5);
   244→}
   245→.footer__details a { color: var(--bos-gold); }
   246→.footer__details a:hover { color: var(--bos-gold-light); }
   247→
   248→.footer__links-title {
   249→  font-weight: 700; font-size: .85rem; color: var(--white);
   250→  letter-spacing: .5px; margin-bottom: 16px; text-transform: uppercase;
   251→}
   252→.footer__link-list { list-style: none; display: flex; flex-direction: column; gap: 8px; }
   253→.footer__link-list a {
   254→  color: rgba(168,180,194,.5); font-size: .85rem; transition: color .2s;
   255→}
   256→.footer__link-list a:hover { color: var(--white); }
   257→
   258→.footer__bottom {
   259→  margin-top: 40px; padding: 18px 0;
   260→  border-top: 1px solid rgba(255,255,255,.05);
   261→  display: flex; align-items: center; justify-content: space-between;
   262→  font-size: .78rem; color: rgba(168,180,194,.35);
   263→}
   264→
   265→/* ===== Page Content (presse, impressum, datenschutz) ===== */
   266→.page-content {
   267→  max-width: 720px; margin: 0 auto;
   268→  padding: calc(var(--nav-h) + 48px) 24px 80px;
   269→}
   270→.page-content h1 { font-size: 1.6rem; font-weight: 800; color: var(--gray-900); margin-bottom: 8px; }
   271→.page-content .subtitle { font-size: .85rem; color: var(--gray-500); margin-bottom: 40px; }
   272→.page-content h2 { font-size: .95rem; font-weight: 700; color: var(--polizei-navy); margin-bottom: 8px; }
   273→.page-content section { margin-bottom: 32px; }
   274→.page-content p { font-size: .9rem; color: var(--gray-700); line-height: 1.7; }
   275→
   276→/* ===== Article Cards (presse) ===== */
   277→.article {
   278→  display: block; margin-bottom: 24px; padding: 24px;
   279→  background: var(--white); border-radius: var(--radius);
   280→  border: 1px solid var(--gray-100);
   281→  transition: border-color .2s, box-shadow .2s;
   282→  text-decoration: none; color: inherit; cursor: pointer;
   283→}
   284→.article:hover {
   285→  border-color: var(--polizei-mid);
   286→  box-shadow: 0 2px 12px rgba(59,90,140,.08);
   287→}
   288→.article__date {
   289→  font-size: .75rem; font-weight: 600; color: var(--polizei-mid);
   290→  text-transform: uppercase; letter-spacing: .5px; margin-bottom: 6px;
   291→}
   292→.article__tag {
   293→  display: inline-block; font-size: .65rem; font-weight: 600;
   294→  padding: 2px 8px; border-radius: 3px; margin-left: 8px;
   295→  letter-spacing: .3px; vertical-align: middle;
   296→}
   297→.article__tag--artikel { background: rgba(58,90,140,.1); color: var(--polizei-mid); }
   298→.article__tag--podcast { background: rgba(212,168,67,.15); color: var(--bos-gold); }
   299→.article__tag--blog { background: rgba(27,42,74,.08); color: var(--polizei-navy); }
