/* ===== Aktuelles Listing ===== */
.aktuelles-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(340px, 1fr));
  gap: 28px;
}
.aktuelles-card {
  display: flex;
  flex-direction: column;
  background: var(--white);
  border: 1px solid var(--gray-100);
  border-radius: var(--radius);
  overflow: hidden;
  transition: border-color .2s, box-shadow .2s;
  text-decoration: none;
  color: inherit;
}
.aktuelles-card:hover {
  border-color: var(--polizei-mid);
  box-shadow: 0 4px 20px rgba(15,26,46,.08);
}
.aktuelles-card__image {
  width: 100%;
  aspect-ratio: 16 / 9;
  overflow: hidden;
}
.aktuelles-card__image img {
  width: 100%;
  height: 100%;
  object-fit: cover;
  display: block;
}
.aktuelles-card__body {
  padding: 22px 24px 26px;
  display: flex;
  flex-direction: column;
  flex: 1;
}
.aktuelles-card__meta {
  display: flex;
  align-items: center;
  gap: 10px;
  margin-bottom: 8px;
}
.aktuelles-card__date {
  font-size: .75rem;
  font-weight: 600;
  color: var(--polizei-mid);
  text-transform: uppercase;
  letter-spacing: .5px;
}
.aktuelles-card__title {
  font-size: 1.05rem;
  font-weight: 700;
  color: var(--gray-900);
  line-height: 1.35;
  margin-bottom: 10px;
}
.aktuelles-card:hover .aktuelles-card__title {
  color: var(--polizei-mid);
}
.aktuelles-card__teaser {
  font-size: .85rem;
  color: var(--gray-700);
  line-height: 1.65;
  margin-bottom: 16px;
  flex: 1;
}
.aktuelles-card__link {
  font-size: .82rem;
  font-weight: 600;
  color: var(--polizei-light);
  transition: color .2s;
}
